'use client'

import { useState } from 'react'
import { Camera, X } from 'lucide-react'

const TIPOS_IMOVEL = ['Apartamento', 'Casa', 'Studio', 'Cobertura', 'Terreno', 'Sala Comercial', 'Outro'] as const
const STATUS = ['Livre', 'Ocupado', 'Em reforma'] as const

export function FormCaptarImovel({ onClose }: { onClose: () => void }) {
  const [titulo, setTitulo] = useState('')
  const [endereco, setEndereco] = useState('')
  const [bairro, setBairro] = useState('')
  const [cidade, setCidade] = useState('')
  const [tipoImovel, setTipoImovel] = useState<(typeof TIPOS_IMOVEL)[number]>('Apartamento')
  const [finalidade, setFinalidade] = useState<'Venda' | 'Locação'>('Venda')
  const [valor, setValor] = useState('')
  const [area, setArea] = useState('')
  const [quartos, setQuartos] = useState('')
  const [proprietario, setProprietario] = useState('')
  const [telefoneProprietario, setTelefoneProprietario] = useState('')
  const [status, setStatus] = useState<(typeof STATUS)[number]>('Livre')
  const [observacoes, setObservacoes] = useState('')

  return (
    <div>
      <div className="flex items-center justify-between mb-5">
        <h2 className="font-serif text-xl font-semibold text-foreground">Captar imóvel</h2>
        <button
          type="button"
          onClick={onClose}
          aria-label="Fechar"
          className="flex size-8 items-center justify-center rounded-full bg-muted text-muted-foreground"
        >
          <X className="size-4" strokeWidth={1.5} />
        </button>
      </div>

      <div className="flex flex-col gap-4">
        {/* Foto */}
        <button
          type="button"
          className="flex flex-col items-center gap-2 rounded-2xl border-2 border-dashed border-border py-8 text-muted-foreground transition-brand active:scale-[0.98]"
        >
          <Camera className="size-8" strokeWidth={1} />
          <span className="text-sm font-medium">Tirar foto do imóvel</span>
          <span className="text-xs text-muted-foreground/70">ou selecionar da galeria</span>
        </button>

        {/* Título */}
        <div>
          <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Título do imóvel *</label>
          <input
            type="text"
            value={titulo}
            onChange={(e) => setTitulo(e.target.value)}
            placeholder="Ex: Apartamento Jardins 3 quartos"
            className="h-12 w-full rounded-2xl border border-border bg-background px-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
          />
        </div>

        {/* Endereço */}
        <div>
          <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Endereço</label>
          <input
            type="text"
            value={endereco}
            onChange={(e) => setEndereco(e.target.value)}
            placeholder="Rua, número, complemento"
            className="h-12 w-full rounded-2xl border border-border bg-background px-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
          />
        </div>

        <div className="grid grid-cols-2 gap-2">
          <div>
            <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Bairro</label>
            <input
              type="text"
              value={bairro}
              onChange={(e) => setBairro(e.target.value)}
              placeholder="Jardins"
              className="h-12 w-full rounded-2xl border border-border bg-background px-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
            />
          </div>
          <div>
            <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Cidade</label>
            <input
              type="text"
              value={cidade}
              onChange={(e) => setCidade(e.target.value)}
              placeholder="São Paulo"
              className="h-12 w-full rounded-2xl border border-border bg-background px-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
            />
          </div>
        </div>

        {/* Tipo */}
        <div>
          <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Tipo</label>
          <select
            value={tipoImovel}
            onChange={(e) => setTipoImovel(e.target.value as (typeof TIPOS_IMOVEL)[number])}
            className="h-12 w-full rounded-2xl border border-border bg-background px-4 text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-ring appearance-none"
          >
            {TIPOS_IMOVEL.map((t) => <option key={t} value={t}>{t}</option>)}
          </select>
        </div>

        {/* Finalidade */}
        <div>
          <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Finalidade</label>
          <div className="flex gap-2">
            {(['Venda', 'Locação'] as const).map((f) => (
              <button
                key={f}
                type="button"
                onClick={() => setFinalidade(f)}
                className={`flex-1 rounded-xl py-2.5 text-sm font-semibold transition-brand ${
                  finalidade === f ? 'bg-primary text-primary-foreground' : 'border border-border bg-card text-muted-foreground'
                }`}
              >
                {f}
              </button>
            ))}
          </div>
        </div>

        {/* Valor e Área */}
        <div className="grid grid-cols-2 gap-2">
          <div>
            <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Valor</label>
            <input
              type="text"
              value={valor}
              onChange={(e) => setValor(e.target.value)}
              placeholder="R$ 890.000"
              className="h-12 w-full rounded-2xl border border-border bg-background px-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
            />
          </div>
          <div>
            <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Área (m²)</label>
            <input
              type="number"
              value={area}
              onChange={(e) => setArea(e.target.value)}
              placeholder="94"
              className="h-12 w-full rounded-2xl border border-border bg-background px-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
            />
          </div>
        </div>

        {/* Quartos */}
        <div>
          <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Quartos</label>
          <div className="flex gap-2">
            {['1', '2', '3', '4', '5+'].map((q) => (
              <button
                key={q}
                type="button"
                onClick={() => setQuartos(q)}
                className={`flex-1 rounded-xl py-2.5 text-sm font-semibold transition-brand ${
                  quartos === q ? 'bg-primary text-primary-foreground' : 'border border-border bg-card text-muted-foreground'
                }`}
              >
                {q}
              </button>
            ))}
          </div>
        </div>

        {/* Status */}
        <div>
          <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Status do imóvel</label>
          <div className="flex gap-2">
            {STATUS.map((s) => (
              <button
                key={s}
                type="button"
                onClick={() => setStatus(s)}
                className={`flex-1 rounded-xl py-2.5 text-xs font-semibold transition-brand ${
                  status === s ? 'bg-primary text-primary-foreground' : 'border border-border bg-card text-muted-foreground'
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>

        {/* Proprietário */}
        <div className="rounded-2xl bg-cream p-4">
          <p className="mb-3 text-xs font-semibold uppercase tracking-wide text-muted-foreground">Dados do proprietário</p>
          <div className="flex flex-col gap-3">
            <input
              type="text"
              value={proprietario}
              onChange={(e) => setProprietario(e.target.value)}
              placeholder="Nome do proprietário"
              className="h-11 w-full rounded-xl border border-border bg-background px-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
            />
            <input
              type="tel"
              value={telefoneProprietario}
              onChange={(e) => setTelefoneProprietario(e.target.value)}
              placeholder="Telefone"
              className="h-11 w-full rounded-xl border border-border bg-background px-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
            />
          </div>
        </div>

        {/* Observações */}
        <div>
          <label className="mb-1.5 block text-xs font-semibold uppercase tracking-wide text-muted-foreground">Observações</label>
          <textarea
            value={observacoes}
            onChange={(e) => setObservacoes(e.target.value)}
            rows={2}
            placeholder="Notas sobre o imóvel..."
            className="w-full resize-none rounded-2xl border border-border bg-background p-4 text-sm text-foreground placeholder:text-muted-foreground focus:outline-none focus:ring-2 focus:ring-ring"
          />
        </div>

        <button
          type="button"
          onClick={onClose}
          className="h-12 w-full rounded-2xl bg-primary text-sm font-semibold text-primary-foreground shadow-lg shadow-primary/20 transition-brand active:scale-[0.98]"
        >
          Cadastrar imóvel
        </button>
      </div>
    </div>
  )
}
